// Evidence: httpsts-performance-regression-recovery-2b23f
// Competency: httpsts-performance-regression-recovery.
// Case 6668: accessible status API serving assistive and low-bandwidth clients.
// Operating constraint: show recovery after the overload input is removed.
// Changed case: change the tenant and prove denial before repository access.
function evidence_httpsts_performance_regression_recovery_2b23f(p95Ms: number, budgetMs: number, eventLoopLagMs: number, utilization: number): { pass: boolean; bottleneck: string } {
  if (p95Ms < 0 || budgetMs <= 0 || eventLoopLagMs < 0 || utilization < 0) {
    return { pass: false, bottleneck: "invalid-measurement" };
  }
  const bottleneck = eventLoopLagMs > 50 ? "event-loop" : utilization > 0.8 ? "capacity" : "none";
  return { pass: p95Ms <= budgetMs && bottleneck === "none", bottleneck };
}
